#include<bits/stdc++.h>
using namespace std;
const int NUM = (1<<24) + 5 , mod = 1e9+7;
int n,m,dp[NUM],b1,b2,sum[NUM];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>sum[1<<(i-1)];
    cin>>m;
    if(m>=1)cin>>b1;
    if(m>=2)cin>>b2;
    dp[0]=1;
    for(int i=1;i<(1<<n);i++){
        int j=i&(-i);
        sum[i]=sum[i^j]+sum[j];
        if(sum[i]==b1||sum[i]==b2)continue;
        for(int k=i,p=0;k;k^=p){
            p=k&(-k);
            dp[i]+=dp[i^p];
            if(dp[i]>=mod)dp[i]-=mod;
        }
    }
    cout<<dp[(1<<n)-1];
    return 0;
}
